mapper.select:
SELECT sp.id, sp.org_id, sp.supply_reason AS supplyType, sp.start_time AS planStartTime, sp.end_time AS planEndTime, sp.affected_households AS affectHouseholds, sp.remark AS remarks, sp.status AS supplyStatus, sp.create_time AS createTime, sp.create_id AS createUser, sp.update_time AS updateTime, sp.update_id AS updateUser, org.organization_name AS enterpriseName, san.district_code, san.street_code, san.detail_address FROM gs_supply_plan sp LEFT JOIN tbl_organization org ON sp.org_id = org.id AND org.deleted = 0 LEFT JOIN gs_supply_area_node san ON sp.org_id = san.org_id AND san.deleted = 0 WHERE sp.deleted = 0
AND DATE(sp.start_time) >= #{planStartTime}
AND DATE(sp.end_time) <= #{planEndTime}
AND sp.status = #{supplyStatus}
AND sp.supply_reason = #{supplyType}
ORDER BY sp.create_time DESC

SELECT
id, org_id, supply_reason, start_time, end_time,
affected_households, remark, status, create_time,
create_id, update_time, update_id, deleted
FROM gs_supply_plan
WHERE deleted = 0

    AND DATE(start_time) >= #{planStartTime}


    AND DATE(end_time) <= #{planEndTime}


    AND status = #{supplyStatus}


    AND supply_reason = #{supplyType}

ORDER BY create_time DESC
